const COLORS = {
  background: 'black',
  brightest: 'white',
  bright: 'brightyellow',
  medium: 'green',
  dim: 'darkgreen',
  fade: 'black'
};

interface Drop {
  x: number;
  y: number;
  length: number;
  speed: number;
  speedCounter: number;
  chars: string[];
}

export interface MatrixOptions {
  density?: number;
  minSpeed?: number;
  maxSpeed?: number;
  minLength?: number;
  maxLength?: number;
  showTimestamp?: boolean;
}

export class MatrixRain {
  private screen: blessed.Widgets.Screen;
  private rainBox: blessed.Widgets.BoxElement;
  private drops: Drop[] = [];
  private columns = 0;
  private rows = 0;
  private running = false;
  private gameLoop: NodeJS.Timeout | undefined = undefined;
  private frameCount = 0;
  private options: Required<MatrixOptions>;

  constructor(options: MatrixOptions = {}) {
    this.options = {
      density: 0.3,
      minSpeed: 0.3,
      maxSpeed: 1.2,
      minLength: 3,
      maxLength: 15,
      showTimestamp: true,
      ...options
    };

    this.screen = blessed.screen({
      smartCSR: true,
      title: 'Nexus Digital Rain'
    });

    this.rainBox = blessed.box({
      parent: this.screen,
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      style: { fg: 'green', bg: 'black' },
      tags: true
    });

    this.updateDimensions();
    this.setupInput();
  }

  private updateDimensions(): void {
    this.columns = typeof this.screen.width === 'number' ? this.screen.width : 80;
    this.rows = typeof this.screen.height === 'number' ? this.screen.height : 24;
  }

  private setupInput(): void {
    this.screen.key(['q', 'Q', 'C-c', 'escape'], () => {
      this.quit();
    });

